//==============================================================================================================
// MRFPitch::ApplyTransformation
//Input: CATIPLMNavInstance * piNavInst, double & ioLastAngle
//
//Function: Rotate or Transform the instantiated pitch part to the given angle
//==============================================================================================================
void MRFPitch::ApplyTransformation(CATIPLMNavInstance * piNavInst, double & ioLastAngle)
{

	CATAngle iAngle = 0.;
	if (!_bReverseSequence)
	{
		iAngle = _PitchAngle + ioLastAngle;
	}
	else if (_bReverseSequence)
	{
		iAngle = ioLastAngle;
	}


	CATMathLine iAxis = CATMathLine();

	double index = this->_ComboTranformIndex;

	switch ((int)index)
	{
	case 1: 
		iAxis.SetLineDirection(CATMathVector(1.0, 0.0, 0.0));
		break;
	case 2: 
		iAxis.SetLineDirection(CATMathVector(-1.0, 0.0, 0.0)); break;
	case 3:
		iAxis.SetLineDirection(CATMathVector(0.0, 1.0, 0.0)); break;
	case 4: 
		iAxis.SetLineDirection(CATMathVector(0.0, -1.0, 0.0));
		break;
	case 5: 
		iAxis.SetLineDirection(CATMathVector(0.0, 0.0, 1.0)); break;
	case 6:
		iAxis.SetLineDirection(CATMathVector(0.0, 0.0, -1.0)); break;
	default:
		break;
	}

	

	double dAngInRad = iAngle * CATDegreeToRadian;
	CATMathTransformation iMat = CATMathTransformation(dAngInRad, iAxis);
	
	if (!_bReverseSequence)
	{
		ioLastAngle = iAngle;
	}
	else if (_bReverseSequence)
	{
		ioLastAngle = iAngle - _PitchAngle;
	}

	if (NULL != piNavInst)
	{
		CATIMovable* piMovable = NULL;
		HRESULT rc = piNavInst->QueryInterface(IID_CATIMovable, (void **)&piMovable);
		if (SUCCEEDED(rc) && (NULL != piMovable) )
		{
			piMovable->SetPosition(iMat, NULL_var);

			piMovable->Release();
			piMovable = NULL;
		}
	}
}

