//==============================================================================================================
// MRFPitch::GetPitchInstanceAtCount
//Input:const int iIdxInst
//output: double & ioLastAngle
//Function: Gets the pitch instance and retrive the last angle
//==============================================================================================================
void MRFPitch::GetPitchInstanceAtCount(const int iIdxInst, double & ioLastAngle, CATListPtrCATIPLMComponent &reorderListOfPitch)
{
	CATUnicodeString strIndx;
	strIndx.BuildFromNum(iIdxInst);

	if (NULL != _AssyProdRef && iIdxInst > 0)
	{
		CATIPLMProducts * pRootPLMProd = NULL;
		if (SUCCEEDED(_AssyProdRef->QueryInterface(IID_CATIPLMProducts, (void **)&pRootPLMProd)) && (NULL != pRootPLMProd))
		{
			CATIPLMProducts * pExistingInst = NULL;
			MRFProdStrServices::GetInstanceAtCount(pRootPLMProd, iIdxInst, pExistingInst);
			if (NULL != pExistingInst)
			{
				CATIAlias_var spInstAlias = pExistingInst;
				if (NULL_var != spInstAlias)
				{
					CATUnicodeString strAliasName = spInstAlias->GetAlias();
					if (-1 != strAliasName.SearchSubString(_PitchName))
					{
						_IntPitchInstanceCounter++;
						if (NULL == _piPLMProduct)
						{
							_piPLMProduct = pExistingInst;
							_piPLMProduct->AddRef();
						}

						SetPitchAngle(pExistingInst);

						CATIPLMNavInstance *  pExistingInstance = NULL;
						pExistingInst->QueryInterface(IID_CATIPLMNavInstance, (void**)&pExistingInstance);
						if (NULL != pExistingInstance)
						{
							CATUnicodeString istrTemp;
							istrTemp.BuildFromNum(_IntPitchInstanceCounter);
							MRFProdStrServices::SetInstanceName(pExistingInstance, _PitchName + "." + istrTemp);

							ApplyTransformationInAssy(pExistingInstance, ioLastAngle);
							//ApplyTransformation(pExistingInstance, ioLastAngle);

							CATBaseUnknown* pInstanceCBU = NULL;
							
							HRESULT hr;
							if (pExistingInstance)
								hr = pExistingInstance->QueryInterface(IID_CATIPLMComponent, (void**)&pInstanceCBU);

							CATIPLMComponent* pInstance = (CATIPLMComponent *)pInstanceCBU;
							if (FAILED(hr) || pInstance == NULL)
								return;

							CATIAlias_var spInstAlias = pInstance;
							CATUnicodeString instName = spInstAlias->GetAlias();
							reorderListOfPitch.Append(pInstance);

							pExistingInstance->Release();
							pExistingInstance = NULL;
						}
					}
					else
					{
						/*if (NULL != _piPLMProduct)
						{
							_piPLMProduct->Release();
							_piPLMProduct = NULL;
						}*/
						_bPitchInstToReplace = TRUE;
						if (CreateInstanceOfPitch(iIdxInst, ioLastAngle))
						{
							_bPitchInstToReplace = FALSE;
						}
					}
				}
				pExistingInst->Release();
				pExistingInst = NULL;
			}
			pRootPLMProd->Release();
			pRootPLMProd = NULL;
		}
	}
}

//-------------------------------------------------------------------------------------------------------------------------
//MRFPitch::InsertInAssy()
//Input: int iIdxInst, CATIPLMProducts * piPLMProduct, double & ioLastAngle
//Function: Pitch Part instanciated is transformed to respective pitch angle measured from last angle.
//--------------------------------------------------------------------------------------------------------------------------
HRESULT MRFPitch::InsertInAssy(const int iIdxInst, CATIPLMProducts * piPLMProduct, double & ioLastAngle)
{
	HRESULT rc = E_FAIL;

	CATUnicodeString strIndx;
	strIndx.BuildFromNum(iIdxInst);

	if (NULL != _AssyProdRef)
	{
		CATIPLMProducts * piAssyRefPLMProduct = NULL;
		if (SUCCEEDED(_AssyProdRef->QueryInterface(IID_CATIPLMProducts, (void **)&piAssyRefPLMProduct)) && (NULL != piAssyRefPLMProduct))
		{
			CATIPLMNavInstance *  pProdInstance = NULL;

			int iChildCount = 0;
			rc = piAssyRefPLMProduct->Count(iChildCount);
			if (SUCCEEDED(rc) && iIdxInst <= iChildCount && _bPitchInstToReplace)
			{
				CATIPLMProducts * pOldInst = NULL;
				MRFProdStrServices::GetInstanceAtCount(piAssyRefPLMProduct, iIdxInst, pOldInst);
				if (NULL != pOldInst)
				{
					rc = MRFProdStrServices::ReplaceInParentRef(piAssyRefPLMProduct, piPLMProduct, pOldInst, pProdInstance);
					pOldInst->Release();
					pOldInst = NULL;
				}
			}
			else
			{
				rc = MRFProdStrServices::InsertInParentRef(piAssyRefPLMProduct, piPLMProduct, _PitchAssyName + "." + strIndx, pProdInstance);
			}
			CATUnicodeString istrTemp;
			istrTemp.BuildFromNum(_IntPitchInstanceCounter);
			MRFProdStrServices::SetInstanceName(pProdInstance, _PitchName + "." + istrTemp);

			if (SUCCEEDED(rc) && NULL != pProdInstance)
			{
				ApplyTransformationInAssy(pProdInstance, ioLastAngle);
				pProdInstance->Release();
				pProdInstance = NULL;
			}
			piAssyRefPLMProduct->Release();
			piAssyRefPLMProduct = NULL;
		}

	}
	return rc;
}

//-------------------------------------------------------------------------------------------------------------------------
//MRFPitch::ApplyTransformationInAssy()
//Input: CATIPLMNavInstance *  pProdInstance, double & ioLastAngle
//Function: Pitch Part instanciated is transformed to respective pitch angle measured from last angle.
//--------------------------------------------------------------------------------------------------------------------------
void MRFPitch::ApplyTransformationInAssy(CATIPLMNavInstance *  pProdInstance, double & ioLastAngle)
{
	HRESULT rc = E_FAIL;
	if (NULL != pProdInstance)
	{
		ApplyTransformation(pProdInstance, ioLastAngle);
		CATIPLMProducts * piPLMProductInstance = NULL;
		if (SUCCEEDED(pProdInstance->QueryInterface(IID_CATIPLMProducts, (void**)&piPLMProductInstance)) && NULL != piPLMProductInstance)
		{
			CATIPLMNavOccurrence * pNavOccurence = NULL;
			rc = pProdInstance->GetFirstLevelOccurrence(pNavOccurence, pNavOccurence);
			if (NULL != pNavOccurence)
			{
				_pPitchNavOccurence = pNavOccurence;

				pNavOccurence->Release();
				pNavOccurence = NULL;
			}

			for (int i = 1; i <= _ListOfPathsOfFeaturesToBeCopied.Size(); i++)
			{
				CATPathElement *pPath = _ListOfPathsOfFeaturesToBeCopied[i];
				if (NULL != pPath)
				{
					pPath->Release();
					pPath = NULL;
				}
			}
			_ListOfPathsOfFeaturesToBeCopied.RemoveAll();

			SetFeaturesToCopy(piPLMProductInstance, _ListOfPathsOfFeaturesToBeCopied);
			
			piPLMProductInstance->Release();
			piPLMProductInstance = NULL;

		}
		else
		{
			rc = E_FAIL;
		}
	}
}

